// Pull reviews out of each Amazon Product SDE response, key each review so we
// can tell new from already-seen across runs, and emit ONE item per NEW review.
// The set of seen review keys persists in workflow static data (per ASIN), so
// re-runs only forward reviews that appeared since the last execution. On the
// first run there is no history, so the most recent reviews (capped per ASIN)
// are treated as new to give the workflow immediate output.
//
// Note: the Amazon Product endpoint returns a sample of the product's reviews,
// not the full chronological history — this tracks reviews as they enter that
// sample. Static data resets if the workflow is re-imported.

const store = $getWorkflowStaticData('global');
store.seenReviews = store.seenReviews || {}; // { asin: [key, ...] }

const cfg = $('Configure Watchlist').first().json;
const MAX_NEW_PER_ASIN = Number(cfg.max_new_per_asin) || 10;
const KEEP_KEYS = 200;

const getBody = (item) => {
  const resp = item && item.json && item.json.response;
  if (!resp || resp.body === undefined) return {};
  if (typeof resp.body === 'string') {
    try { return JSON.parse(resp.body); } catch (e) { return {}; }
  }
  return resp.body;
};

const str = (v) => String(v == null ? '' : v).trim();
const numOrNull = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const n = parseFloat(String(v).replace(/[^0-9.]/g, ''));
  return Number.isFinite(n) ? n : null;
};

const keyOf = (asin, r) => {
  const id = str(r.id || r.review_id);
  if (id) return asin + '::' + id;
  return [
    asin,
    str(r.username || r.author || r.reviewer).toLowerCase(),
    str(r.date || r.review_date),
    str(r.title || r.review_title).slice(0, 60).toLowerCase(),
  ].join('::');
};

const splitItems = $('Split Amazon ASINs').all();
const out = [];

$input.all().forEach((item, i) => {
  const body = getBody(item);
  const meta = (splitItems[i] && splitItems[i].json) || {};
  const asin = str(meta.asin) || str(body.asin);
  if (!asin) return;
  const productName = str(body.name || body.title || body.product_title) || asin;

  let reviews = body.reviews;
  if (reviews && !Array.isArray(reviews)) reviews = reviews.recent_reviews || reviews.reviews || [];
  if (!Array.isArray(reviews)) reviews = body.customer_reviews || body.top_reviews || [];
  if (!Array.isArray(reviews)) return;

  const seen = new Set(store.seenReviews[asin] || []);
  const freshKeys = [];
  let taken = 0;

  for (const r of reviews) {
    if (!r || typeof r !== 'object') continue;
    const key = keyOf(asin, r);
    if (!key || seen.has(key)) continue;
    seen.add(key);
    freshKeys.push(key);
    if (taken >= MAX_NEW_PER_ASIN) continue; // record as seen, but don't forward
    taken++;
    out.push({
      json: {
        asin,
        product_name: productName,
        label: str(meta.label) || productName,
        review_id: str(r.id || r.review_id),
        review_key: key,
        title: str(r.title || r.review_title),
        body: str(r.review || r.text || r.body || r.content),
        stars: numOrNull(r.stars ?? r.rating),
        username: str(r.username || r.author || r.reviewer),
        date: str(r.date || r.review_date),
        verified: !!(r.verified_purchase ?? r.verified),
        review_url: str(r.url || r.link),
        scraped_at: new Date().toISOString(),
      },
      pairedItem: { item: i },
    });
  }

  // Persist the updated seen-set for this ASIN, trimmed to the most recent keys.
  const merged = (store.seenReviews[asin] || []).concat(freshKeys);
  store.seenReviews[asin] = merged.slice(-KEEP_KEYS);
});

return out;

// Normalize the LLM classification and re-attach the review metadata.
// With response_format json_object the Basic LLM Chain surfaces parsed fields
// directly on item.json; older versions wrap them under text / output /
// response — handle both shapes.

return $input.all().map((item, i) => {
  const j = item.json || {};

  let parsed = j;
  const looksParsed = j.sentiment !== undefined || Array.isArray(j.feature_tags);
  if (!looksParsed) {
    const raw = j.text || j.output || j.response || '';
    try { parsed = typeof raw === 'string' ? JSON.parse(raw) : raw; }
    catch (e) { parsed = {}; }
  }

  const meta = ($('Extract New Reviews').itemMatching(i) || {}).json || {};
  const tags = Array.isArray(parsed.feature_tags)
    ? parsed.feature_tags.map((t) => String(t).trim()).filter(Boolean)
    : [];

  const sentiment = String(parsed.sentiment || 'unknown').toLowerCase().trim();

  // Notion caps each rich_text block at 2000 chars, so pre-build the review
  // block here and clip it. Long Amazon reviews would otherwise fail the
  // Append node with a body validation error.
  const clip = (s, n) => {
    s = String(s == null ? '' : s);
    return s.length > n ? s.slice(0, n - 1).trimEnd() + '…' : s;
  };
  const reviewBody = String(meta.body || '(no review text)');
  const reviewBlock = clip((meta.title ? meta.title + '\n\n' : '') + reviewBody, 1990);

  // Turn the Amazon review date ("Reviewed in the United States on July 1, 2026")
  // into an ISO date so it can fill a real Notion Date property that sorts
  // chronologically. Falls back to the scrape date when the string can't be
  // parsed, so the Date property is never empty — Notion rejects empty dates.
  const MONTHS = { january: 1, february: 2, march: 3, april: 4, may: 5, june: 6, july: 7, august: 8, september: 9, october: 10, november: 11, december: 12 };
  const parseDate = (s) => {
    const m = String(s == null ? '' : s).match(/([A-Za-z]+)\s+(\d{1,2}),\s*(\d{4})/);
    if (m && MONTHS[m[1].toLowerCase()]) {
      const mm = String(MONTHS[m[1].toLowerCase()]).padStart(2, '0');
      const dd = String(m[2]).padStart(2, '0');
      return m[3] + '-' + mm + '-' + dd;
    }
    return String(meta.scraped_at || '').slice(0, 10) || null;
  };
  const reviewDateIso = parseDate(meta.date);

  return {
    json: {
      ...meta,
      sentiment,
      feature_tags: tags,
      feature_tags_str: tags.join(', ') || '(none)',
      ai_summary: String(parsed.summary || '').trim(),
      review_block: reviewBlock,
      review_date_iso: reviewDateIso,
    },
    pairedItem: { item: i },
  };
});
